  {icon:'💎', name:'TypeScript', color:'#3b82f6'},
  {icon:'🐍', name:'Python', color:'#10b981'},
  {icon:'🔵', name:'Go', color:'#00c8ff'},
  {icon:'🦀', name:'Rust', color:'#f97316'},
  {icon:'🔴', name:'Laravel', color:'#ef4444'},
  {icon:'⚛️', name:'React', color:'#06b6d4'},
  {icon:'▲', name:'Next.js', color:'#aaa'},
  {icon:'💚', name:'Vue.js', color:'#10b981'},
  {icon:'🟢', name:'Node.js', color:'#22c55e'},
  {icon:'🌊', name:'Tailwind', color:'#0ea5e9'},
  {icon:'🗄️', name:'MySQL', color:'#f59e0b'},
  {icon:'🐘', name:'Postgres', color:'#6366f1'},
  {icon:'🔴', name:'Redis', color:'#ef4444'},
  {icon:'🔥', name:'PyTorch', color:'#f97316'},
  {icon:'🧠', name:'TensorFlow', color:'#fbbf24'},
  {icon:'🐳', name:'Docker', color:'#0ea5e9'},
  {icon:'🐙', name:'GitHub', color:'#aaa'},
  {icon:'🎨', name:'Figma', color:'#a855f7'},
];

const tg = document.getElementById('tech-grid');
techStack.forEach(t => {
  const el = document.createElement('div');
  el.className = 'tech-chip';
  el.style.setProperty('--tc', t.color);
  el.innerHTML = `${t.icon}${t.name}`;
  tg.appendChild(el);
});

const skills = [
  {name:'Laravel / PHP', pct:95, c:'#7c3aed', c2:'#a855f7'},
  {name:'React / Next.js', pct:92, c:'#00c8ff', c2:'#06b6d4'},
  {name:'Python / ML', pct:85, c:'#10b981', c2:'#34d399'},
  {name:'System Architecture', pct:90, c:'#f59e0b', c2:'#fbbf24'},
  {name:'Node.js / APIs', pct:88, c:'#22c55e', c2:'#4ade80'},
  {name:'AI Integration', pct:87, c:'#a855f7', c2:'#c084fc'},
  {name:'Vue.js / TypeScript', pct:83, c:'#06b6d4', c2:'#67e8f9'},
  {name:'DevOps / Docker', pct:78, c:'#f97316', c2:'#fb923c'},
];

const sl = document.getElementById('skills-left');
const sr = document.getElementById('skills-right');
skills.forEach((s, i) => {
  const div = document.createElement('div');
  div.className = 'skill-bar-item';
  div.innerHTML = `


      ${s.name}
      ${s.pct}%





    `;
  (i % 2 === 0 ? sl : sr).appendChild(div);
});

setTimeout(() => {
  document.querySelectorAll('.skill-bar-fill').forEach(el => {
    el.style.width = el.dataset.width;
  });
}, 400);

const exp = [
  {role:'Full-Stack Developer', company:'QuantumPlus (Pvt) Ltd', period:'Aug 2025 – Present', dot:''},
  {role:'Full-Stack Developer Intern', company:'Ministry of Education, Eastern Province', period:'Aug 2025 – Present', dot:''},
  {role:'Software Engineer Intern', company:'DuskQ (Pvt) Ltd', period:'Aug 2025 – Mar 2026', dot:'purple'},
  {role:'Associate Software Engineer', company:'QuantumPlus (Pvt) Ltd', period:'Feb 2025 – Aug 2025', dot:'purple'},
  {role:'Software Engineer Intern', company:'QuantumPlus (Pvt) Ltd', period:'Dec 2024 – Feb 2025', dot:'purple'},
];
const tl = document.getElementById('timeline');
exp.forEach(e => {
  tl.innerHTML += `







${e.role}

${e.company}

${e.period}

  `;
});

const projects = [
  {icon:'🏛️', title:'ResolveQ', desc:'AI-powered governance complaint management with intelligent case prioritization. Award-winning with published research.', color:'#00c8ff', tags:['AI','Governance','Laravel']},
  {icon:'🎓', title:'EMS360', desc:'AI-driven education management ecosystem covering academics, HR, finance and analytics for large institutions.', color:'#a855f7', tags:['AI','EdTech','FullStack']},
  {icon:'⚗️', title:'ChemNexus AI', desc:'AI-powered chemistry learning platform with adaptive content and intelligent question prediction. National Award Winner.', color:'#fbbf24', tags:['AI','Education','NLP']},
  {icon:'⚖️', title:'LexAI', desc:'Virtual legal intelligence platform supporting lawyers and judiciary with intelligent legal insights and automation.', color:'#10b981', tags:['AI','LegalTech','NLP']},
  {icon:'🌾', title:'AgriTrace360', desc:'Agricultural traceability platform with IoT, AI shelf-life prediction and blockchain for transparent supply chains.', color:'#f97316', tags:['IoT','Blockchain','AI']},
  {icon:'🏢', title:'SCOApp', desc:'Enterprise-grade digital office platform enabling correspondence workflows, appointments, and executive dashboards.', color:'#f472b6', tags:['Enterprise','Government','FullStack']},
];
const pg = document.getElementById('projects-grid');
projects.forEach(p => {
  pg.innerHTML += `



${p.icon}

${p.title}

${p.desc}

${p.tags.map(t => `${t}`).join('')}
  `;
});

const awards = [
  {trophy:'🥇', name:'National Ingenuity Award 2025 — Best Innovative Product', project:'ChemNexus AI', event:'National Level, Sri Lanka, 2025'},
  {trophy:'🏅', name:'Best Practice Innovation in Efficient & Accountable Governance', project:'ResolveQ', event:'BP-IPAG 2025, Asia-Pacific'},
  {trophy:'🏅', name:'Best Practice Innovation in Digital Transformation & Innovation', project:'EMS360', event:'BP-IPAG 2025, Asia-Pacific'},
  {trophy:'🏅', name:'Best Practice Innovation in Digital Transformation & Innovation', project:'SCOApp', event:'BP-IPAG 2025, Asia-Pacific'},
  {trophy:'🏅', name:'Best Practice Innovation in People Power & Human Capital', project:'ChemNexus AI', event:'BP-IPAG 2025, Asia-Pacific'},
];
const al = document.getElementById('awards-list');
awards.forEach(a => {
  al.innerHTML += `


    ${a.trophy}



${a.name}

Project: ${a.project}

${a.event}

  `;
});

const pubs = [
  {year:'2026', title:'ChemnexQ: Smart Learning Platform', venue:'AIMDA 2026 · University of Peradeniya'},
  {year:'2025', title:'ChemNexus AI — AI-Powered Educational Platform', venue:'BP-IPAG Symposium · ISSN: 3051-5998'},
  {year:'2025', title:'EMS360 — AI-powered Education Management Ecosystem', venue:'BP-IPAG Symposium · ISSN: 3051-5998'},
  {year:'2025', title:'SCOApp — Smart Cloud Office Platform', venue:'BP-IPAG Symposium · ISSN: 3051-5998'},
  {year:'2025', title:'ResolveQ — AI-Powered Complaint Management for Governance', venue:'BP-IPAG Symposium · ISSN: 3051-5998'},
];
const pl = document.getElementById('pub-list');
pubs.forEach(p => {
  pl.innerHTML += `


    ${p.year}



${p.title}

${p.venue}

  `;
});

// Counters
function animateCount(id, target, suffix='') {
  let start = 0;
  const el = document.getElementById(id);
  const step = Math.ceil(target / 40);
  const timer = setInterval(() => {
    start = Math.min(start + step, target);
    el.textContent = start + suffix;
    if (start >= target) clearInterval(timer);
  }, 30);
}
setTimeout(() => {
  animateCount('stat-yrs', 2, '+');
  animateCount('stat-aw', 5);
  animateCount('stat-pub', 5);
  animateCount('stat-proj', 12, '+');
  setTimeout(() => {
    document.getElementById('gh1').textContent = '500+';
    document.getElementById('gh2').textContent = '120+';
    document.getElementById('gh3').textContent = '800+';
  }, 800);
}, 300);

// Typing animation
const lines = [
  '> Building AI-powered systems...',
  '> 4× National Award Winner 🏆',
  '> Full-Stack · AI · Architect',
  '> Solving real-world problems at scale',
];
let li = 0, ci = 0, deleting = false;
const typed = document.getElementById('typed-text');
function typeLoop() {
  const line = lines[li];
  if (!deleting) {
    typed.textContent = line.slice(0, ++ci);
    if (ci === line.length) { deleting = true; setTimeout(typeLoop, 1800); return; }
  } else {
    typed.textContent = line.slice(0, --ci);
    if (ci === 0) { deleting = false; li = (li + 1) % lines.length; }
  }
  setTimeout(typeLoop, deleting ? 40 : 70);
}
typeLoop();

// Particles
const pc = document.getElementById('particles');
for (let i = 0; i < 25; i++) {
  const p = document.createElement('div');
  p.className = 'particle';
  p.style.cssText = `left:${Math.random()*100}%;bottom:0;--dur:${6+Math.random()*8}s;--delay:${Math.random()*8}s;--drift:${(Math.random()-.5)*2};background:${['#00c8ff','#a855f7','#10b981','#fbbf24'][Math.floor(Math.random()*4)]}`;
  pc.appendChild(p);
}
